def extract_paragraphs(result: AnalyzeResult) -> list:
    """
    Extract all paragraphs from the document, including bounding regions and offsets.

    Args:
        result (AnalyzeResult): The result object from the document analysis.

    Returns:
        list: A list of dictionaries containing content, role, bounding region, page number, and span info.
    """
    try:
        paragraphs = []
        if result.paragraphs:
            # Sort by offset (best practice)
            result.paragraphs.sort(
                key=lambda p: (p.spans[0].offset if p.spans else 0)
            )

            for paragraph in result.paragraphs:
                para_info = {
                    "content": paragraph.content,
                    "offset": paragraph.spans[0].offset if paragraph.spans else None,
                    "length": paragraph.spans[0].length if paragraph.spans else None,
                    "pages": [],
                    "bounding_regions": []
                }

                if paragraph.bounding_regions:
                    for region in paragraph.bounding_regions:
                        page = region.page_number
                        polygon_raw = region.polygon  # list of floats [x1, y1, x2, y2, ...]
                        polygon = [(polygon_raw[i], polygon_raw[i + 1]) for i in range(0, len(polygon_raw), 2)] if polygon_raw else None

                        para_info["pages"].append(page)
                        para_info["bounding_regions"].append({
                            "page": page,
                            "polygon": polygon
                        })
                else:
                    para_info["pages"].append(None)
                    para_info["bounding_regions"].append(None)

                paragraphs.append(para_info)

        logger.info(f"extract_paragraphs: Extracted {len(paragraphs)} structured paragraphs")
        return paragraphs

    except Exception as e:
        logger.error(f"extract_paragraphs - Failed to extract all paragraphs from the document: {str(e)}")
        raise

def search_paragraphs(paragraphs: list, keywords: list) -> dict:
    """
    Search paragraphs for specific keywords (case-sensitive) and return all matches,
    including page number and bounding regions.

    Args:
        paragraphs (list): List of paragraph objects, each containing 'content', 'bounding_regions', and 'page_number'.
        keywords (list): List of keywords to search for.

    Returns:
        dict: A dictionary mapping keywords to all matching paragraph's content, page number, and bounding regions.
    """
    try:
        matches = {keyword: [] for keyword in keywords}  # Initialize empty lists for each keyword

        for keyword in keywords:
            for paragraph in paragraphs:
                if keyword in paragraph["content"]:  # Case-sensitive match
                    # Extract relevant details: content, page number, bounding regions
                    paragraph_info = {
                        "content": paragraph["content"],
                        "page_number": paragraph["pages"][0] if paragraph["pages"] else "N/A",
                        "bounding_regions": [
                            {
                                "page": region["page"],
                                "polygon": region["polygon"]
                            }
                            for region in paragraph["bounding_regions"]
                        ] if paragraph["bounding_regions"] else []
                    }

                    matches[keyword].append(paragraph_info)  # Add to the list of matches for this keyword

            # If no match is found, store empty data
            if not matches[keyword]:
                matches[keyword] = [{"content": "", "page_number": "N/A", "bounding_regions": []}]

        return matches

    except Exception as e:
        logger.error(f"search_paragraphs - Error searching paragraphs for specific keywords: {str(e)}")
        raise

def is_date(value):
    """
    Check if a value is a date in DD/MM/YYYY format.

    Args:
        value: The value to check (string or other type).

    Returns:
        bool: True if the value matches DD/MM/YYYY, False otherwise.
    """
    try:
        if not isinstance(value, str):
            return False
        return bool(re.match(r'^\d{2}/\d{2}/\d{4}$', value))

    except Exception as e:
        logger.error(f"is_date - Failed to check if a value is a date: {str(e)}")
        raise

def process_meter_reading_dates(df):
    """
    Process a DataFrame to propagate dates in PREV READ and CURRENT READ columns based on the format.

    Args:
        df: Input pandas DataFrame.

    Returns:
        pandas.DataFrame: Processed DataFrame with dates propagated.
    """
    try:
        df = df.copy()

        previous_read_col = None
        current_read_col = None
        previous_read_date = None
        current_previous_read_date = None
        date_pattern = r'\d{2}/\d{2}/\d{4}'

        for col in df.columns:
            if col.startswith('PREV READ'):
                previous_read_col = col
                match = re.search(date_pattern, col)
                if match:
                    previous_read_date = match.group()
            elif col.startswith('CURRENT READ'):
                current_read_col = col
                match = re.search(date_pattern, col)
                if match:
                    current_previous_read_date = match.group()

        rename_dict = {}
        if previous_read_col and previous_read_col != 'PREV READ':
            rename_dict[previous_read_col] = 'PREV READ'
        if current_read_col and current_read_col != 'CURRENT READ':
            rename_dict[current_read_col] = 'CURRENT READ'
        if rename_dict:
            df = df.rename(columns=rename_dict)

        if previous_read_date:
            df['PREV READ'] = df['PREV READ'].apply(lambda x: previous_read_date if pd.notnull(x) and str(x).strip() else x)
        else:
            current_date = None
            for idx, row in df.iterrows():
                read_val = row['PREV READ']
                if is_date(read_val):
                    current_date = read_val
                if pd.notnull(read_val) and not is_date(read_val) and current_date:
                    df.at[idx, 'PREV READ'] = current_date

        if current_previous_read_date:
            df['CURRENT READ'] = df['CURRENT READ'].apply(lambda x: current_previous_read_date if pd.notnull(x) and str(x).strip() else x)
        else:
            previous_date = None
            for idx, row in df.iterrows():
                curr_val = row['CURRENT READ']
                if is_date(curr_val):
                    previous_date = curr_val
                if pd.notnull(curr_val) and not is_date(curr_val) and previous_date:
                    df.at[idx, 'CURRENT READ'] = previous_date

        return df

    except Exception as e:
        logger.error(f"process_meter_reading_dates - Failed to process meter reading dates: {str(e)}")
        raise
